const current = $('Load Exception + Shipment').item.json;
const historyRows = $input.all().map((item) => item.json);
const latest = historyRows[0] || {};
const shipmentAgeDays = Math.max(0, Math.floor((Date.now() - new Date(current.created_at).getTime()) / (1000 * 60 * 60 * 24)));

return [{
  json: {
    exception_id: current.exception_id,
    shipment_id: current.shipment_id,
    exception_data: {
      exception_type: current.exception_type,
      reason: current.reason,
      severity_hint: current.severity_hint,
      overdue_hours: Number(current.overdue_hours || 0),
      carrier: current.carrier,
      destination: current.destination,
      failed_attempts: current.failed_attempts || 0
    },
    history_context: {
      previous_exception_count: historyRows.length,
      last_exception_type: latest.exception_type || 'none',
      shipment_age_days: shipmentAgeDays
    }
  }
}];
